"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[718],{7833:e=>{e.exports=JSON.parse('{"lang":"de","resources":{"landing":{"meta":{"title":"Linguist \u2013 Die datenschutzfreundliche \xdcbersetzungs-Erweiterung f\xfcr Chrome und Firefox","description":"Eine Browser-Erweiterung, die Webseiten, markierten Text und Untertitel \xfcbersetzt. Funktioniert in Echtzeit und unterst\xfctzt Offline-\xdcbersetzungen."},"navigation":{"features":{"content":"Funktionen"},"blog":{"content":"Blog"},"docs":{"content":"Dokumentation"},"github":{"content":"GitHub"}},"install":{"chrome":"F\xfcr Chrome installieren","firefox":"F\xfcr Firefox installieren"},"sections":{"hero":{"title":"Alles direkt im Browser \xfcbersetzen","description":"Linguist ist eine Browser-Erweiterung, die Texte in Echtzeit \xfcbersetzt.\\n\\nOb ganze Webseiten, markierte Texte, Netflix-Untertitel oder private Nachrichten \u2013 alles l\xe4sst sich nahtlos \xfcbersetzen. \xdcbersetzte Texte k\xf6nnen angeh\xf6rt und wichtige Begriffe im pers\xf6nlichen W\xf6rterbuch gespeichert werden, um auch offline neue W\xf6rter zu lernen.\\n\\nLinguist ist eine moderne und datenschutzfreundliche Alternative zu Google Translate. Jetzt kostenlos ausprobieren."},"opensource":{"title":"Open Source","content":"Linguist ist eine kostenlose <0>Open-Source-Erweiterung</0> f\xfcr \xdcbersetzungen im Browser. Es werden keine Nutzerdaten gesammelt oder verkauft.\\n\\nMit einer <1>Spende</1> l\xe4sst sich Linguist unterst\xfctzen, damit das Projekt unabh\xe4ngig bleibt und die hohe Qualit\xe4t bewahrt wird.\\n\\nTeilen Sie Linguist gerne in den sozialen Medien, um das Projekt bekannter zu machen."},"support":{"title":"Support","content":"Bei Fragen k\xf6nnen Sie uns gerne kontaktieren <0/>.\\nFalls Sie einen Fehler gefunden haben und ein GitHub-Konto besitzen, <1>erstellen Sie bitte ein Issue</1>."},"createdBy":{"content":"Entwickelt von <0/>."}},"features":{"title":"Funktionen","items":{"offlineTranslation":{"title":"Offline-\xdcbersetzung und Datenschutz","content":"Mit dem integrierten Offline-\xdcbersetzer werden Texte direkt auf dem eigenen Ger\xe4t \xfcbersetzt. Die Inhalte bleiben privat und werden nicht \xfcber das Internet verschickt.\\n\\nDiese Funktion l\xe4sst sich in den Einstellungen aktivieren, um h\xf6chste Vertraulichkeit bei E-Mails, Dokumenten oder pers\xf6nlichen Nachrichten zu gew\xe4hrleisten.\\n\\nZudem erm\xf6glicht der Offline-\xdcbersetzer das \xdcbersetzen von Webseiten ganz ohne Internetverbindung \u2013 besonders praktisch auf Reisen."},"fullPageTranslation":{"title":"\xdcbersetzung ganzer Webseiten","content":"Schnelle und hochwertige \xdcbersetzungen ganzer Webseiten mit nur wenigen Klicks.\\n\\nEin Tastenk\xfcrzel sorgt f\xfcr sofortige Ergebnisse. F\xe4hrt man mit der Maus \xfcber den \xfcbersetzten Text, wird das Original angezeigt. Selbst private Seiten hinter Logins oder Paywalls lassen sich problemlos \xfcbersetzen.\\n\\nZus\xe4tzlich k\xf6nnen automatische \xdcbersetzungsregeln basierend auf der Sprache oder Domain eingerichtet werden.\\n\\nLinguist greift dabei nur minimal in die Webseite ein: Es werden ausschlie\xdflich Textbausteine ausgetauscht, sodass das urspr\xfcngliche Layout und die Bedienbarkeit vollst\xe4ndig erhalten bleiben.\\n\\nF\xfcr mehrsprachige Meetings in Zoom, Google Meet und Microsoft Teams l\xe4sst sich zudem eine Echtzeit-\xdcbersetzung aktivieren."},"selectedTextTranslation":{"title":"\xdcbersetzung von markiertem Text","content":"Unbekannte W\xf6rter in einem Online-Artikel entdeckt?\\nEinfach den gew\xfcnschten Text markieren und auf die \xdcbersetzen-Schaltfl\xe4che klicken.\\n\\nSowohl der Originaltext als auch die \xdcbersetzung k\xf6nnen angeh\xf6rt werden. Wichtige Begriffe lassen sich im pers\xf6nlichen W\xf6rterbuch speichern, um sie sp\xe4ter zu wiederholen."},"textTranslation":{"title":"Schnelle Text\xfcbersetzung","content":"Schnell etwas \xfcbersetzen? Ein Klick auf das Linguist-Symbol gen\xfcgt, um den Text direkt einzugeben.\\n\\nDas Wechseln zwischen Tabs oder das \xd6ffnen externer \xdcbersetzungs-Webseiten entf\xe4llt. Die \xdcbersetzung erfolgt direkt im Browser \u2013 mit dem bevorzugten \xdcbersetzungsdienst."},"knowledgeBase":{"title":"Aufbau einer pers\xf6nlichen Wissensdatenbank","content":"Jede \xdcbersetzung wird im Verlauf gespeichert, und wichtige Begriffe k\xf6nnen dem pers\xf6nlichen W\xf6rterbuch hinzugef\xfcgt werden. Das W\xf6rterbuch und der \xdcbersetzungsverlauf lassen sich jederzeit durchsuchen.\\n\\nSo geht nichts verloren \u2013 auch nicht bei intensiven Recherchen oder langen Lerneinheiten.\\n\\nDa das W\xf6rterbuch auch offline funktioniert, ist Linguist ideal f\xfcr alle, die Sprachen lernen oder auf Reisen st\xe4ndigen Zugriff auf ihre Vokabeln ben\xf6tigen."},"customTranslators":{"title":"Benutzerdefinierte \xdcbersetzer","content":"Mit Linguist l\xe4sst sich der bevorzugte \xdcbersetzungsdienst frei w\xe4hlen.\\n\\nBeliebte Anbieter wie Google, Yandex und Microsoft werden mit \xfcber 100 verf\xfcgbaren Sprachen direkt unterst\xfctzt.\\n\\nSollte ein gew\xfcnschter Dienst fehlen, kann dieser einfach als <0>benutzerdefinierter \xdcbersetzer</0> hinzugef\xfcgt werden.\\n\\nSo l\xe4sst sich jedes beliebige \xdcbersetzungssystem integrieren \u2013 von modernen KI-Diensten wie ChatGPT, DeepL, DeepSeek und Gemini bis hin zu lokalen \xdcbersetzern, die direkt auf dem eigenen Ger\xe4t laufen, wie etwa Ollama oder LibreTranslate."}}},"faq":{"title":"FAQ","items":{"whatIsLinguist":{"title":"Was ist Linguist?","content":"Linguist ist eine datenschutzfreundliche \xdcbersetzungs-Erweiterung f\xfcr Chrome und Firefox.\\n\\nDamit lassen sich ganze Webseiten, markierte Texte, Untertitel und Nachrichten direkt im Browser \xfcbersetzen, ohne auf externe \xdcbersetzungs-Webseiten wechseln zu m\xfcssen."},"whyLinguist":{"title":"Warum sollte man Linguist nutzen?","content":"Es gibt viele Browser-Erweiterungen zum \xdcbersetzen von Webseiten, und einige Browser haben sogar integrierte \xdcbersetzer. Warum also Linguist?\\n\\nDie meisten integrierten \xdcbersetzer und Erweiterungen sind in ihrer Flexibilit\xe4t eingeschr\xe4nkt. Viele verlassen sich auf einen einzigen Anbieter wie Google Translate oder Microsoft Bing, w\xe4hrend Firefox einen eigenen Offline-\xdcbersetzer anbietet. In den meisten F\xe4llen l\xe4sst sich der Dienst nicht frei w\xe4hlen.\\n\\nWenn die \xdcbersetzungsqualit\xe4t f\xfcr den eigenen Bedarf nicht ausreicht oder das Senden privater Texte an Drittanbieter ein No-Go ist, bieten viele Tools keine gute Alternative.\\n\\nZudem konzentrieren sich viele Werkzeuge nur auf eine einzige Aufgabe: Einige \xfcbersetzen nur ganze Seiten, andere nur markierten Text.\\n\\nGleichzeitig sind einige Erweiterungen stark auf Monetarisierung ausgelegt. Funktionen wie ein \xdcbersetzungsverlauf oder ein pers\xf6nliches W\xf6rterbuch erfordern oft ein Abonnement, und manchmal werden selbst grundlegende Dinge wie ein dunkles Design als Premium-Funktion verkauft.\\n\\nLinguist verfolgt einen anderen Ansatz. Es ist als praktisches und vielseitiges Werkzeug konzipiert. Der \xdcbersetzungsdienst kann frei gew\xe4hlt und jederzeit gewechselt werden \u2013 oder man f\xfcgt einfach eigene, benutzerdefinierte \xdcbersetzer hinzu.\\n\\nDar\xfcber hinaus vereint Linguist alles an einem Ort: Ganze Webseiten, markierte Texte, Untertitel und Nachrichten lassen sich nahtlos \xfcbersetzen, w\xe4hrend wichtige Begriffe im Verlauf und im pers\xf6nlichen W\xf6rterbuch festgehalten werden."},"theLinguistLogo":{"title":"Warum ist das Logo von Linguist der Turmbau zu Babel?","content":"Das Logo von Linguist ist vom <wiki>Turmbau zu Babel</wiki> inspiriert, einer der \xe4ltesten Geschichten \xfcber Sprache und Kommunikation.\\n\\nDer Erz\xe4hlung nach sprachen die Menschen einst dieselbe Sprache und versuchten, einen Turm bis in den Himmel zu bauen. Der Turm wurde nie vollendet, und die Menschheit wurde in viele verschiedene Sprachen aufgeteilt. Seitdem machen sprachliche Barrieren die Kommunikation oft zu einer Herausforderung.\\n\\nLinguist wurde entwickelt, um genau dieses Problem zu l\xf6sen.\\n\\nDer Turm zu Babel im Logo erinnert an diese Geschichte: viele Sprachen, viele Kulturen und das stetige menschliche Bestreben, einander zu verstehen. Linguist hilft dabei, diese Br\xfccken zu bauen, indem es \xdcbersetzungen einfach, flexibel und direkt im Browser zug\xe4nglich macht.\\n\\nDas Logo spiegelt auch den Geist des Projekts wider. Linguist ist nicht einfach nur eine weitere Benutzeroberfl\xe4che f\xfcr \u201eGoogle Translate\u201c. Es wird von Menschen entwickelt, denen Sprachen, Datenschutz und offene Technologien am Herzen liegen. Der Turmbau zu Babel steht f\xfcr Neugier, das Lernen und die \xdcberzeugung, dass sprachliche Vielfalt die Menschen zusammenbringen sollte, anstatt sie zu trennen."},"imageTranslation":{"title":"Warum \xfcbersetzt Linguist keinen Text in Bildern?","content":"Linguist konzentriert sich auf zuverl\xe4ssige und hochwertige \xdcbersetzungsfunktionen.\\n\\nWir haben verschiedene Ans\xe4tze zur \xdcbersetzung von Text in Bildern untersucht. Derzeit liefern die meisten verf\xfcgbaren L\xf6sungen keine konsistenten Ergebnisse, insbesondere wenn sie direkt im Browser ausgef\xfchrt werden \u2013 was jedoch entscheidend ist, um die Privatsph\xe4re der Nutzer zu sch\xfctzen.\\n\\nAus diesem Grund bietet Linguist momentan keine Bild\xfcbersetzung an. Wir verzichten lieber auf Funktionen, die unseren Qualit\xe4tsstandards nicht entsprechen.\\n\\nSobald wir einen zuverl\xe4ssigen und datenschutzfreundlichen Weg finden, die Bild\xfcbersetzung umzusetzen, werden wir diese Funktion gerne hinzuf\xfcgen."},"howTranslatePages":{"title":"Wie \xfcbersetzt Linguist Webseiten?","content":"Linguist kann ganze Webseiten mit nur wenigen Klicks \xfcbersetzen. Die \xdcbersetzung l\xe4sst sich \xfcber die Schaltfl\xe4che der Erweiterung oder ein Tastenk\xfcrzel starten.\\n\\nDer Originaltext bleibt dabei immer zug\xe4nglich: F\xe4hrt man mit der Maus \xfcber den \xfcbersetzten Text, wird das Original eingeblendet."},"offlineTranslation":{"title":"Kann Linguist Seiten offline \xfcbersetzen?","content":"Ja. Linguist verf\xfcgt \xfcber einen integrierten Offline-\xdcbersetzer, mit dem Texte \xfcbersetzt werden k\xf6nnen, ohne Daten \xfcber das Internet zu senden.\\n\\nDas sch\xfctzt die Privatsph\xe4re und erm\xf6glicht es, Inhalte auch ganz ohne Internetverbindung zu \xfcbersetzen."},"privacy":{"title":"Ist Linguist datenschutzfreundlich?","content":"Ja. Linguist wurde mit einem starken Fokus auf Datenschutz entwickelt.\\n\\nDie Erweiterung sammelt oder verkauft keine Nutzerdaten. Bei der Nutzung des <offline-translator>Offline-\xdcbersetzers</offline-translator> werden alle \xdcbersetzungen vollst\xe4ndig lokal auf dem eigenen Ger\xe4t verarbeitet."},"supportedBrowsers":{"title":"Welche Browser werden von Linguist unterst\xfctzt?","content":"Linguist ist f\xfcr Chrome und Firefox verf\xfcgbar. Es funktioniert auch in anderen Chromium-basierten Browsern, die Chrome-Erweiterungen unterst\xfctzen.\\n\\nDar\xfcber hinaus l\xe4uft Linguist in Android-Browsern mit Erweiterungs-Support, wie beispielsweise Firefox f\xfcr Android und einigen Chromium-basierten Browsern."},"selectedText":{"title":"Kann Linguist markierten Text \xfcbersetzen?","content":"Ja. Einfach den gew\xfcnschten Text auf einer beliebigen Webseite markieren und die \xdcbersetzen-Schaltfl\xe4che nutzen, um ihn sofort zu \xfcbersetzen.\\n\\nDie \xdcbersetzung kann zudem angeh\xf6rt und im pers\xf6nlichen W\xf6rterbuch gespeichert werden."},"customTranslators":{"title":"Kann ich meinen eigenen \xdcbersetzungsdienst nutzen?","content":"Ja. Linguist unterst\xfctzt <custom-translator>benutzerdefinierte \xdcbersetzer</custom-translator>, mit denen sich zus\xe4tzliche \xdcbersetzungsdienste integrieren lassen.\\n\\nSo k\xf6nnen externe APIs oder lokale \xdcbersetzungssysteme wie <libre-translate>LibreTranslate</libre-translate> oder <ollama>Ollama</ollama> angebunden werden."},"isFree":{"title":"Ist Linguist kostenlos?","content":"Ja. Linguist ist vollst\xe4ndig kostenlos und <linguist>Open Source</linguist>.\\n\\nDas Projekt wird von der Community getragen und kann optional <donations>mit einer Spende unterst\xfctzt werden</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pt","langName":"portugu\xeas","url":"https://linguister.io/pt"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh","langName":"\u4e2d\u6587","url":"https://linguister.io/zh"}]}')}}]);